package com.clinipet.controller;
import com.clinipet.dao.DashboardDAO; import jakarta.servlet.*; import jakarta.servlet.annotation.WebServlet; import jakarta.servlet.http.*; import java.io.IOException;
@WebServlet(name="CitaEstadoServlet", urlPatterns={"/citas/realizada","/citas/cancelar","/enfermero/citas/aceptar","/enfermero/citas/realizada","/enfermero/citas/cancelar"})
public class CitaEstadoServlet extends HttpServlet { protected void doPost(HttpServletRequest request,HttpServletResponse response)throws ServletException,IOException{ if(request.getSession(false)==null||request.getSession(false).getAttribute("usuario")==null){response.sendRedirect(request.getContextPath()+"/login");return;} int id=Integer.parseInt(request.getParameter("id")); String path=request.getServletPath(), estado="PENDIENTE"; if(path.contains("realizada"))estado="REALIZADA"; else if(path.contains("cancelar"))estado="CANCELADA"; else if(path.contains("aceptar"))estado="ACEPTADA"; new DashboardDAO().actualizarEstadoCita(id,estado); response.sendRedirect(request.getContextPath()+(path.startsWith("/enfermero")?"/enfermero/dashboard?ok=1":"/dashboard?ok=1")); } }
